sql:
SELECT area_name, population_density
FROM areas
WHERE crime_rate = (SELECT MAX(crime_rate) FROM areas);

SELECT area_name
FROM areas
WHERE crime_rate = (SELECT MAX(crime_rate) FROM areas);

SELECT AVG(crime_rate) AS average_crime_rate
FROM areas
WHERE population_density > (SELECT AVG(population_density) FROM areas);

